index bd225bcc0635..8d07141ba74e 100644
--- a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
+++ b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
@@ -29,6 +29,7 @@
 #include "llvm/IR/IRBuilder.h"
 #include "llvm/IR/PatternMatch.h"
 #include "llvm/Support/CommandLine.h"
+#include "llvm/Support/MathExtras.h"
 #include "llvm/Transforms/Utils/Local.h"
 #include "llvm/Transforms/Utils/LoopUtils.h"
 #include <numeric>
@@ -1447,8 +1448,15 @@ static ScalarizationResult canScalarizeAccess(VectorType *VecTy, Value *Idx,

   unsigned IntWidth = Idx->getType()->getScalarSizeInBits();
   APInt Zero(IntWidth, 0);
-  APInt MaxElts(IntWidth, NumElements);
-  ConstantRange ValidIndices(Zero, MaxElts);
+  // Check if NumElements fits in IntWidth bits. If not, then any index value
+  // is necessarily less than NumElements (since max index is 2^IntWidth - 1).
+  // In that case, the valid range is the full set of index values.
+  ConstantRange ValidIndices = ConstantRange::getFull(IntWidth);
+  if (isUIntN(IntWidth, NumElements)) {
+    // NumElements fits, so we can compute the precise valid range.
+    APInt MaxElts(IntWidth, NumElements);
+    ValidIndices = ConstantRange(Zero, MaxElts);
+  }
   ConstantRange IdxRange(IntWidth, true);

   if (isGuaranteedNotToBePoison(Idx, &AC)) {
@@ -1460,7 +1468,7 @@ static ScalarizationResult canScalarizeAccess(VectorType *VecTy, Value *Idx,

   // If the index may be poison, check if we can insert a freeze before the
   // range of the index is restricted.
-  Value *IdxBase;
+  Value *IdxBase = nullptr;
   ConstantInt *CI;
   if (match(Idx, m_And(m_Value(IdxBase), m_ConstantInt(CI)))) {
     IdxRange = IdxRange.binaryAnd(CI->getValue());
@@ -1468,15 +1476,14 @@ static ScalarizationResult canScalarizeAccess(VectorType *VecTy, Value *Idx,
     IdxRange = IdxRange.urem(CI->getValue());
   }

+  // If no pattern matched, we cannot freeze a specific base, so treat as unsafe.
+  if (!IdxBase)
+    return ScalarizationResult::unsafe();
+
   if (ValidIndices.contains(IdxRange))
     return ScalarizationResult::safeWithFreeze(IdxBase);
   return ScalarizationResult::unsafe();
 }
